SET @green_thumb_id = (SELECT id FROM partners WHERE businessName = 'Green Thumb Lawn Care' LIMIT 1);
SET @job1 = (SELECT id FROM jobs WHERE serviceAddress = '4821 Mockingbird Ln, Dallas, TX 75209' LIMIT 1);
SET @job2 = (SELECT id FROM jobs WHERE serviceAddress = '2209 Swiss Ave, Dallas, TX 75204' LIMIT 1);
