-- Inbound leads for Scoop Duke (sent by Green Thumb)
INSERT INTO opportunities (jobId, sourcePartnerId, receivingPartnerId, opportunityType, opportunityCategory, description, aiConfidence, status, estimatedJobValue, sentAt, createdAt)
VALUES
  (@job1, @green_thumb_id, @scoop_duke_id, 'pet_waste_removal', 'Pet & Animal Services', 'Dog waste visible throughout backyard. Homeowner has 2 large dogs. Recurring service opportunity — estimated bi-weekly visits.', 0.94, 'sent', 180.00, DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY)),
  (@job2, @green_thumb_id, @scoop_duke_id, 'pet_waste_removal', 'Pet & Animal Services', 'Heavy waste accumulation near fence. Likely 3–4 weeks without service. Good candidate for monthly plan.', 0.91, 'sent', 120.00, DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY)),
  (@job3, @green_thumb_id, @scoop_duke_id, 'pet_waste_removal', 'Pet & Animal Services', 'Two large dogs, waste not cleaned up in visible areas. Homeowner may not have a current service provider.', 0.88, 'accepted', 150.00, DATE_SUB(NOW(), INTERVAL 8 DAY), DATE_SUB(NOW(), INTERVAL 8 DAY));

